from django.conf import settings
from django.contrib.auth import login
from django.core.exceptions import SuspiciousOperation
from django.http import HttpResponse
from django.shortcuts import redirect
from django.views import View
from lxml import etree
import base64
import requests

class SAMLResponseView(View):

    def post(self, request):
        saml_response = request.POST.get('SAMLResponse')
        if not saml_response:
            return HttpResponse("Missing SAMLResponse", status=400)
        
        xml_data = base64.b64decode(saml_response)
        try:
            self.validate_xml(xml_data)
            user_info = self.parse_saml_response(xml_data)
            self.create_user_session(user_info, request)
            return redirect('/success/')  # Redirect to a success page
        except Exception as e:
            return HttpResponse(f"Error processing SAML response: {str(e)}", status=400)

    def validate_xml(self, xml_data):
        try:
            schema_root = etree.XMLSchema(etree.parse(settings.SAML_SCHEMA_PATH))
            xml_doc = etree.fromstring(xml_data)
            schema_root.assertValid(xml_doc)
        except (etree.DocumentInvalid, IOError) as e:
            raise SuspiciousOperation("Invalid SAML XML: " + str(e))

    def parse_saml_response(self, xml_data):
        xml_doc = etree.fromstring(xml_data)
        namespace = '{urn:oasis:names:tc:SAML:2.0:assertion}'
        name_id = xml_doc.find('.//{}NameID'.format(namespace)).text
        attributes = {}
        for attr in xml_doc.findall('.//{}Attribute'.format(namespace)):
            attr_name = attr.get('Name')
            attr_value = attr.find('{}AttributeValue'.format(namespace)).text
            attributes[attr_name] = attr_value
        return {'name_id': name_id, 'attributes': attributes}

    def create_user_session(self, user_info, request):
        user, created = self.get_or_create_user(user_info)
        login(request, user)

    def get_or_create_user(self, user_info):
        from django.contrib.auth.models import User
        user, created = User.objects.get_or_create(username=user_info['name_id'])
        # Assuming 'attributes' contain the necessary user detail
        for key, value in user_info['attributes'].items():
            setattr(user, key, value)
        user.save()
        return user, created